import React from 'react';
import { Handle, Position, useReactFlow } from 'reactflow';

export const BaseNode = ({ id, label, children, handles = [] }) => {
  const { deleteElements } = useReactFlow();

  const handleDelete = () => {
    deleteElements({ nodes: [{ id }] });
  };

  return (
    <div style={{
      background: 'rgba(25, 25, 30, 0.85)',
      backdropFilter: 'blur(15px)',
      border: '1px solid rgba(255, 255, 255, 0.08)',
      borderRadius: '16px',
      padding: '20px',
      boxShadow: '0 15px 35px rgba(0, 0, 0, 0.4)',
      minWidth: '220px',
      color: '#f8fafc',
      position: 'relative' // Needed for the absolute delete button
    }}>
      {/* Delete Button */}
      <button 
        onClick={handleDelete}
        style={{
          position: 'absolute',
          top: '10px',
          right: '10px',
          background: 'transparent',
          border: 'none',
          color: '#94a3b8',
          cursor: 'pointer',
          fontSize: '16px',
          fontWeight: 'bold'
        }}
      >
        ×
      </button>

      <div style={{ 
        fontWeight: '700', 
        marginBottom: '15px', 
        fontSize: '14px', 
        color: '#94a3b8',
        textTransform: 'uppercase',
        letterSpacing: '0.05em'
      }}>
        {label}
      </div>

      <div style={{ fontSize: '14px' }}>
        {children}
      </div>

      {handles.map((h, i) => (
        <Handle 
          key={i} 
          type={h.type} 
          position={h.position} 
          id={`${id}-${h.id}`} 
          style={{ 
            top: h.top, 
            background: '#6366f1', 
            width: '10px', 
            height: '10px',
            border: '2px solid #0a0a0c'
          }} 
        />
      ))}
    </div>
  );
};
